'use strict';

// MODULES //

import numelDimension from '@stdlib/ndarray/base/numel-dimension';
import getStride from '@stdlib/ndarray/base/stride';
import getOffset from '@stdlib/ndarray/base/offset';
import getData from '@stdlib/ndarray/base/data-buffer';
import ndarraylike2scalar from '@stdlib/ndarray/base/ndarraylike2scalar';
import { ndarray as strided } from './../../../../../ext/base/dcusumors';


// MAIN //

/**
* Computes the cumulative sum of a one-dimensional double-precision floating-point ndarray using ordinary recursive summation.
*
* ## Notes
*
* -   The function expects the following ndarrays:
*
*     -   a one-dimensional input ndarray.
*     -   a one-dimensional output ndarray.
*     -   a zero-dimensional ndarray containing the initial sum.
*
* @param {ArrayLikeObject<Object>} arrays - array-like object containing ndarrays
* @returns {Object} output ndarray
*
* @example
* import Float64Vector from '@stdlib/ndarray/vector/float64';
* import scalar2ndarray from '@stdlib/ndarray/from-scalar';
*
* var x = new Float64Vector( [ 1.0, 3.0, 4.0, 2.0 ] );
* var y = new Float64Vector( [ 0.0, 0.0, 0.0, 0.0 ] );
*
* var initial = scalar2ndarray( 0.0, {
*     'dtype': 'float64'
* });
*
* var z = dcusumors( [ x, y, initial ] );
* // returns <ndarray>[ 1.0, 4.0, 8.0, 10.0 ]
*
* var bool = ( z === y );
* // returns true
*/
function dcusumors( arrays ) {
	var x = arrays[ 0 ];
	var y = arrays[ 1 ];
	var v = ndarraylike2scalar( arrays[ 2 ] );
	strided( numelDimension( x, 0 ), v, getData( x ), getStride( x, 0 ), getOffset( x ), getData( y ), getStride( y, 0 ), getOffset( y ) ); // eslint-disable-line max-len
	return y;
}


// EXPORTS //

export default dcusumors;
